        <script>
            // Tạo bông tuyết
            function createSnowflakes() {
                const snowContainer = document.getElementById("snow");
                const snowflakes = ["❅", "❆", "❄"];
                const numberOfSnowflakes = 20; // Giảm số lượng để cải thiện hiệu suất

                for (let i = 0; i < numberOfSnowflakes; i++) {
                    const snowflake = document.createElement("div");
                    snowflake.className = "snowflake";
                    snowflake.innerHTML =
                        snowflakes[
                            Math.floor(Math.random() * snowflakes.length)
                        ];
                    snowflake.style.left = Math.random() * 100 + "%";
                    snowflake.style.animationDuration =
                        Math.random() * 3 + 5 + "s"; // 5-8 giây
                    snowflake.style.animationDelay = Math.random() * 2 + "s";
                    snowflake.style.opacity = Math.random() * 0.6 + 0.4;
                    snowContainer.appendChild(snowflake);
                }
            }

            // Chuyển đổi trạng thái đóng/mở panel
            function togglePanel(panelId) {
                const panel = document.getElementById(panelId);
                panel.classList.toggle("collapsed");
            }

            // Hàm làm sạch và định dạng hiển thị dữ liệu mảng
            function formatArrayData() {
                const dataValues = document.querySelectorAll(".data-value");
                dataValues.forEach((el) => {
                    let text = el.innerText.trim();
                    // Kiểm tra xem dữ liệu có phải dạng mảng JSON ["...", "..."] hoặc [] không
                    if (text.startsWith("[") && text.endsWith("]")) {
                        try {
                            const parsed = JSON.parse(text);
                            if (Array.isArray(parsed)) {
                                if (parsed.length === 0) {
                                    el.innerText = "—"; // Hiển thị dấu gạch ngang nếu mảng trống
                                } else {
                                    el.innerText = parsed.join(", "); // Nối các phần tử bằng dấu phẩy
                                }
                            }
                        } catch (e) {
                            // Nếu parse lỗi (do định dạng không chuẩn), dùng regex xóa ký tự thừa
                            let cleanText = text.replace(/[\[\]"]/g, "").trim();
                            if (cleanText === "") {
                                el.innerText = "—";
                            } else {
                                el.innerText = cleanText.replace(/,/g, ", ");
                            }
                        }
                    }
                });
            }

            // Khởi tạo
            document.addEventListener("DOMContentLoaded", function () {
                createSnowflakes();

                // Chạy hàm định dạng dữ liệu
                formatArrayData();

                // Tự động đóng một số panel để tiết kiệm không gian
                const panelsToCollapse = [
                    "player-relations",
                    "tavern-inventory",
                ];
                panelsToCollapse.forEach((id) => {
                    document.getElementById(id).classList.add("collapsed");
                });
            });
        </script>
    </body>
</html>
