}

.snowflake.blur {
    filter: blur(1px);
    opacity: 0.6;
}

@keyframes fall {
    from {
        transform: translateY(-100vh) rotate(0deg);
    }
    to {
        transform: translateY(100vh) rotate(360deg);
    }
}

@keyframes sway {
    0%, 100% { transform: translateX(0); }
