    }
    to {
        text-shadow:
            2px 2px 0 #b8860b,
            0 0 25px rgba(255, 215, 0, 0.8),
            0 0 50px rgba(255, 215, 0, 0.5),
            0 0 75px rgba(255, 215, 0, 0.3);
    }
}

@keyframes textFloat {
    0%, 100% { transform: translateY(0) scale(1); }
    50% { transform: translateY(-2px) scale(1.02); }
}

/* 面板容器 */
.panels {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 10px;
    /* animation: panelsFadeIn 1s ease-out; */
}

@keyframes panelsFadeIn {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}

/* 增强版木质面板 */
.panel {
    background: linear-gradient(180deg, #6b4423 0%, #523318 50%, #3e2514 100%);
    border: 2px solid #2e1a0f;
    border-radius: 4px;
    overflow: hidden;
    box-shadow:
        inset -1px -1px 2px rgba(0,0,0,0.5),
        2px 2px 4px rgba(0,0,0,0.3),
        0 0 15px rgba(0,0,0,0.2);
    transition: all 0.3s ease;
    /* animation: panelBreathe 4s ease-in-out infinite;
    animation-delay: calc(var(--panel-index) * 0.2s); */
    position: relative;
}

@keyframes panelBreathe {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.01); }
}

.panel:hover {
    transform: translateY(-3px) scale(1.02);
    box-shadow:
        inset -1px -1px 2px rgba(0,0,0,0.5),
        4px 4px 12px rgba(0,0,0,0.4),
        0 0 30px rgba(255, 215, 0, 0.2);
    z-index: 10;
}

/* 面板发光边框 */
.panel::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    border-radius: 4px;
    padding: 1px;
    background: linear-gradient(45deg, #ffd700, #ff6347, #00bfff, #9370db);
    -webkit-mask:
        linear-gradient(#fff 0 0) content-box,
        linear-gradient(#fff 0 0);
    mask:
        linear-gradient(#fff 0 0) content-box,
        linear-gradient(#fff 0 0);
    -webkit-mask-composite: xor;
    mask-composite: exclude;
    opacity: 0;
    transition: opacity 0.3s;
    /* animation: borderRotate 3s linear infinite; */
}

.panel:hover::before {
    opacity: 0.5;
}

@keyframes borderRotate {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

.panel-header {
    background: linear-gradient(180deg, #4a3018 0%, #3e2514 100%);
    padding: 6px 8px;
    cursor: pointer;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid #2e1a0f;
    user-select: none;
    position: relative;
    overflow: hidden;
}

/* 面板标题悬停光效 */
.panel-header::after {
    content: '';
    position: absolute;
    top: 50%;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg,
        transparent,
        rgba(255, 255, 255, 0.2),
        transparent);
    transition: left 0.5s;
}

.panel-header:hover::after {
    left: 100%;
}

.panel-header:hover {
    background: linear-gradient(180deg, #5a3a20 0%, #4a3018 100%);
}

.panel-title {
    color: #ffd700;
    font-size: 9px;
    text-shadow: 1px 1px 0 #000, 0 0 5px rgba(255, 215, 0, 0.3);
    /* animation: titleGlow 2s ease-in-out infinite; */
}

@keyframes titleGlow {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.8; }
}

.collapse-icon {
    transition: transform 0.3s;
    /* animation: iconPulse 2s ease-in-out infinite; */
}

@keyframes iconPulse {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.1); }
}

.panel.collapsed .collapse-icon {
    transform: rotate(-90deg);
}

.panel-content {
    padding: 8px;
    max-height: 300px;
    overflow-y: auto;
    transition: all 0.3s ease-out;
    position: relative;
}

/* 内容渐变遮罩 */
.panel-content::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 20px;
    background: linear-gradient(to bottom, transparent, #3e2514);
    pointer-events: none;
}

.panel.collapsed .panel-content {
    max-height: 0;
    padding: 0 8px;
    opacity: 0;
}

/* 增强版数据项 */
.data-item {
    display: flex;
    justify-content: space-between;
    padding: 3px 0;
    border-bottom: 1px dotted #3e2514;
    transition: all 0.2s;
    position: relative;
}

.data-item::before {
    content: '';
    position: absolute;
    left: -8px;
    top: 0;
    bottom: 0;
    width: 3px;
    background: #ffd700;
    opacity: 0;
    transition: opacity 0.3s;
}

.data-item:hover {
    padding-left: 8px;
    background: rgba(255, 215, 0, 0.05);
}

.data-item:hover::before {
    opacity: 1;
}

.data-item:last-child {
    border-bottom: none;
}

.data-label {
    color: #daa520;
    font-size: 7px;
    /* animation: labelPulse 3s ease-in-out infinite; */
}

@keyframes labelPulse {
    0%, 100% { opacity: 0.9; }
    50% { opacity: 1; }
}

.data-value {
    color: #f5deb3;
    font-size: 7px;
    text-align: right;
    max-width: 60%;
    word-break: break-all;
    animation: valueUpdate 0.5s ease-out;   
}

@keyframes valueUpdate {
    from {
        opacity: 0;
        transform: translateX(10px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

/* 特殊值样式增强 */
.gold {
    color: #ffd700;
    text-shadow: 0 0 3px rgba(255, 215, 0, 0.5);
    animation: goldShine 2s ease-in-out infinite;
