// Hệ thống tuyết rơi siêu cấp
function createEnhancedSnowflakes() {
    const snowContainer = document.getElementById('snow');
    const snowflakes = ['❅', '❆', '❄', '✧', '✦', '⋆'];
    const numberOfSnowflakes = 50; // Tăng số lượng

    for (let i = 0; i < numberOfSnowflakes; i++) {
        const snowflake = document.createElement('div');
        snowflake.className = 'snowflake';
        if (Math.random() > 0.7) {
            snowflake.classList.add('blur');
        }
        snowflake.innerHTML = snowflakes[Math.floor(Math.random() * snowflakes.length)];
        snowflake.style.left = Math.random() * 100 + '%';
        snowflake.style.fontSize = (Math.random() * 0.8 + 0.4) + 'em';
        snowflake.style.animationDuration = Math.random() * 5 + 10 + 's';
        snowflake.style.animationDelay = Math.random() * 5 + 's';
        snowflake.style.opacity = Math.random() * 0.6 + 0.4;
        snowContainer.appendChild(snowflake);
    }
}

// Tạo hạt ma pháp
function createMagicParticles() {
    const container = document.getElementById('particles-js');
    setInterval(() => {
        const particle = document.createElement('div');
        particle.className = 'magic-particle';
        particle.style.left = Math.random() * 100 + '%';
        particle.style.animationDuration = Math.random() * 5 + 10 + 's';
        particle.style.animationDelay = Math.random() * 2 + 's';
        container.appendChild(particle);

        // Dọn dẹp hạt cũ
        setTimeout(() => {
            particle.remove();
        }, 15000);
    }, 2000);
}

// Chuyển đổi trạng thái đóng/mở panel (Phiên bản nâng cao)
function togglePanel(panel) {
    panel.classList.toggle('collapsed');

    // Thêm hoạt ảnh chuyển đổi
    const content = panel.querySelector('.panel-content');
    if (!panel.classList.contains('collapsed')) {
        content.style.animation = 'none';
        setTimeout(() => {
            content.style.animation = 'panelsFadeIn 0.5s ease-out';
        }, 10);
    }
}

// Mô phỏng hoạt ảnh cập nhật dữ liệu
function simulateDataUpdate() {
    const values = document.querySelectorAll('.data-value');
    setInterval(() => {
        const randomValue = values[Math.floor(Math.random() * values.length)];
        randomValue.style.animation = 'none';
        setTimeout(() => {
            randomValue.style.animation = 'valueUpdate 0.5s ease-out';
        }, 10);
    }, 3000);
}

// Khởi tạo tất cả hiệu ứng động
document.addEventListener('DOMContentLoaded', function() {
    // Ẩn hoạt ảnh tải trang
    setTimeout(() => {
        document.getElementById('loading').style.display = 'none';
    }, 1000);

    // Khởi tạo tất cả hiệu ứng
    createEnhancedSnowflakes();
    createMagicParticles();
    simulateDataUpdate();

    // Tăng cường hiệu ứng hover panel
    const panels = document.querySelectorAll('.panel');
    panels.forEach((panel, index) => {
        panel.addEventListener('mouseenter', function() {
            this.style.zIndex = '20';
        });
        panel.addEventListener('mouseleave', function() {
            setTimeout(() => {
                this.style.zIndex = '2';
            }, 300);
        });
    });

    // Tạm dừng hoạt ảnh khi trang không hiển thị (Tối ưu hóa hiệu suất)
    document.addEventListener('visibilitychange', function() {
        const animations = document.querySelectorAll('*');
        if (document.hidden) {
            animations.forEach(el => {
                if (el.style.animationPlayState !== 'paused') {
                    el.style.animationPlayState = 'paused';
                    el.dataset.wasPlaying = 'true';
                }
            });
        } else {
            animations.forEach(el => {
                if (el.dataset.wasPlaying === 'true') {
                    el.style.animationPlayState = 'running';
                    delete el.dataset.wasPlaying;
                }
            });
        }
    });
});
</script>

