// Script quản lý tự động chuyển đổi mùa - Phiên bản nâng cao
// Chức năng: Dựa vào thời gian trò chơi trong hệ thống MVU để tự động chuyển đổi mục Lorebook về mùa

// Lắng nghe sự kiện
eventOn(tavern_events.GENERATION_ENDED, async () => {
    await checkAndUpdateSeason();
});

eventOn(tavern_events.CHAT_CHANGED, async () => {
    setTimeout(async () => {
        await checkAndUpdateSeason();
    }, 1500);
});

// Hàm kiểm tra cốt lõi
async function checkAndUpdateSeason() {
    try {
        // 1. Lấy dữ liệu MVU
        const chatVariables = getVariables({ type: 'chat' });

        if (!chatVariables || !chatVariables.stat_data) {
            console.log('[Quản Lý Mùa] Dữ liệu MVU chưa khởi tạo');
            return;
        }

        // Lấy thời gian thế giới (Sử dụng đường dẫn biến đã dịch: world.time)
        const worldTimeArray = chatVariables.stat_data?.world?.time;
        if (!worldTimeArray || !Array.isArray(worldTimeArray)) {
            console.log('[Quản Lý Mùa] Không thể lấy thời gian thế giới');
            return;
        }

        const worldTime = worldTimeArray[0];
        console.log('[Quản Lý Mùa] Thời gian thế giới hiện tại:', worldTime);

        // Phân tích tháng (Định dạng tiếng Việt: "tháng MM")
        // Regex bắt: "tháng" + khoảng trắng (tùy chọn) + 1 hoặc 2 chữ số
        const monthMatch = worldTime.match(/tháng\s*(\d{1,2})/i);
        if (!monthMatch) {
            console.log('[Quản Lý Mùa] Không thể phân tích tháng từ chuỗi thời gian');
            return;
        }

        const month = parseInt(monthMatch[1]);

        // Xác định mùa
        let currentSeason = '';
        // Xuân: 3, 4, 5
        if (month >= 3 && month <= 5) {
            currentSeason = 'Mùa Xuân';
        } 
        // Hạ: 6, 7, 8
        else if (month >= 6 && month <= 8) {
            currentSeason = 'Mùa Hạ';
        } 
        // Thu: 9, 10, 11
        else if (month >= 9 && month <= 11) {
            currentSeason = 'Mùa Thu';
        } 
        // Đông: 12, 1, 2
        else {
            currentSeason = 'Mùa Đông';
        }

        console.log(`[Quản Lý Mùa] Mùa hiện tại: ${currentSeason} (Tháng ${month})`);

        // 2. Lấy Worldbook - Thử nhiều cách
        let worldbookName = null;
        let worldbookEntries = null;

        // Cách 1: Thử lấy Worldbook gắn với chat hiện tại
        try {
            worldbookName = getChatWorldbookName('current');
            if (worldbookName) {
                console.log('[Quản Lý Mùa] Tìm thấy Worldbook của chat:', worldbookName);
                worldbookEntries = await getWorldbook(worldbookName);
            }
        } catch (e) {
            console.log('[Quản Lý Mùa] getChatWorldbookName thất bại:', e);
        }

        // Cách 2: Nếu không có, thử lấy Worldbook của nhân vật
        if (!worldbookEntries) {
            try {
                const charWorldbooks = getCharWorldbookNames('current');
                if (charWorldbooks && charWorldbooks.primary) {
                    worldbookName = charWorldbooks.primary;
                    console.log('[Quản Lý Mùa] Tìm thấy Worldbook chính của nhân vật:', worldbookName);
                    worldbookEntries = await getWorldbook(worldbookName);
                }
            } catch (e) {
                console.log('[Quản Lý Mùa] getCharWorldbookNames thất bại:', e);
            }
        }

        // Cách 3: Lấy tất cả Worldbook, tìm cái nào chứa mục mùa
        if (!worldbookEntries) {
            try {
                const allWorldbooks = getWorldbookNames();
                console.log('[Quản Lý Mùa] Tất cả Worldbook:', allWorldbooks);

                for (const wbName of allWorldbooks) {
                    const entries = await getWorldbook(wbName);
                    const hasSeasonEntry = entries.some(e =>
                        e.name && e.name.startsWith('[Season]')
                    );

                    if (hasSeasonEntry) {
                        worldbookName = wbName;
                        worldbookEntries = entries;
                        console.log('[Quản Lý Mùa] Tìm thấy Worldbook chứa mục mùa:', wbName);
                        break;
                    }
                }
            } catch (e) {
                console.log('[Quản Lý Mùa] Quét Worldbook thất bại:', e);
            }
        }

        if (!worldbookEntries) {
            console.log('[Quản Lý Mùa] ⚠️ Không tìm thấy bất kỳ Worldbook khả dụng nào');
            console.log('[Quản Lý Mùa] Vui lòng đảm bảo:');
            console.log('  1. Worldbook đã được tạo và chứa các mục về mùa');
            console.log('  2. Worldbook đã được gắn vào chat hoặc nhân vật hiện tại');
            console.log('  3. Tên mục mùa bắt đầu bằng "[Season]"');
            return;
        }

        // 3. Cập nhật mục mùa
        // Mapping tên mùa với tên mục trong Lorebook
        const seasonComments = {
            'Mùa Xuân': '[Season]Không khí mùa xuân',
            'Mùa Hạ': '[Season]Không khí mùa hạ',
            'Mùa Thu': '[Season]Không khí mùa thu',
            'Mùa Đông': '[Season]Không khí mùa đông'
        };

        let hasUpdates = false;

        for (const [season, commentTag] of Object.entries(seasonComments)) {
            const entry = worldbookEntries.find(e => e.name === commentTag);

            if (entry) {
                const shouldEnable = (season === currentSeason);

                if (entry.enabled !== shouldEnable) {
                    entry.enabled = shouldEnable;
                    hasUpdates = true;
                    console.log(`[Quản Lý Mùa] Mục ${season} -> ${shouldEnable ? 'Bật' : 'Tắt'}`);
                }
            }
        }

        // 4. Lưu cập nhật
        if (hasUpdates) {
            await replaceWorldbook(worldbookName, worldbookEntries);
            console.log('[Quản Lý Mùa] ✓ Đã cập nhật mục mùa');

            // Làm mới hiển thị trình chỉnh sửa
            if (typeof builtin !== 'undefined' && builtin.reloadEditorDebounced) {
                builtin.reloadEditorDebounced(worldbookName, false);
            }
        } else {
            console.log('[Quản Lý Mùa] Mục mùa đã là mới nhất');
        }

    } catch (error) {
        console.error('[Quản Lý Mùa] Lỗi:', error);
    }
}

// Hàm kích hoạt thủ công (có thể gọi trong console)
window.triggerSeasonCheck = checkAndUpdateSeason;

// Khởi tạo
(async () => {
    console.log('[Quản Lý Mùa] Script phiên bản nâng cao đã tải');
    console.log('[Quản Lý Mùa] Có thể sử dụng triggerSeasonCheck() để kích hoạt kiểm tra thủ công');

    // Trễ thực hiện kiểm tra lần đầu
    setTimeout(async () => {
        await checkAndUpdateSeason();
    }, 2000);
})();

// Script tự động chuyển đổi cấp bậc danh vọng
// Chức năng: Dựa vào biến "player.playerReputation" trong MVU để tự động bật tắt mục Lorebook tương ứng

// Cấu hình cấp bậc danh vọng
// Lưu ý: 'comment' phải khớp chính xác với Tên mục (Memo) hoặc Dòng đầu tiên trong Lorebook
const REPUTATION_LEVELS = [
    { min: 0, max: 99, name: 'Vô danh tiểu tốt', comment: '[Reputation]Vô danh tiểu tốt(0-99)' },
    { min: 100, max: 999, name: 'Mới bộc lộ tài năng', comment: '[Reputation]Mới bộc lộ tài năng(100-999)' },
    { min: 1000, max: 9999, name: 'Có chút danh tiếng', comment: '[Reputation]Có chút danh tiếng(1000-9999)' },
    { min: 10000, max: 99999, name: 'Danh nhân thành phố', comment: '[Reputation]Danh nhân thành phố(10000-99999)' },
    { min: 100000, max: 999999, name: 'Truyền Kỳ Vương Quốc', comment: '[Reputation]Truyền Kỳ Vương Quốc(100000-999999)' }
];

// Ghi lại cấp độ danh vọng hiện tại để phát hiện thay đổi
let currentReputationLevel = null;

// Lắng nghe sự kiện cập nhật biến MVU
if (typeof Mvu !== 'undefined' && Mvu.events) {
    eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, async (mvuData) => {
        await checkAndUpdateReputation(mvuData);
    });
}

// Lắng nghe sự kiện kết thúc tạo văn bản
eventOn(tavern_events.GENERATION_ENDED, async () => {
    // Lấy dữ liệu MVU mới nhất
    const chatVariables = getVariables({ type: 'chat' });
    if (chatVariables && chatVariables.stat_data) {
        await checkAndUpdateReputation(chatVariables);
    }
});

// Lắng nghe sự kiện chuyển đổi cuộc trò chuyện
eventOn(tavern_events.CHAT_CHANGED, async () => {
    // Đặt lại ghi chép cấp độ hiện tại
    currentReputationLevel = null;

    // Kiểm tra trễ để đảm bảo dữ liệu MVU đã tải xong
    setTimeout(async () => {
        const chatVariables = getVariables({ type: 'chat' });
        if (chatVariables && chatVariables.stat_data) {
            await checkAndUpdateReputation(chatVariables);
        }
    }, 1500);
});

// Hàm kiểm tra cốt lõi
async function checkAndUpdateReputation(mvuData) {
    try {
        // 1. Lấy giá trị danh vọng người chơi
        let playerReputation = 0;

        // Cố gắng lấy giá trị từ dữ liệu MVU (Sử dụng đường dẫn biến đã dịch: player.playerReputation)
        if (mvuData && mvuData.stat_data) {
            const reputationArray = mvuData.stat_data?.player?.playerReputation;

            if (reputationArray && Array.isArray(reputationArray)) {
                playerReputation = parseInt(reputationArray[0]); // Đảm bảo là số nguyên
                console.log('[Quản Lý Danh Vọng] Danh vọng hiện tại:', playerReputation);
            } else {
                console.log('[Quản Lý Danh Vọng] Không thể lấy dữ liệu danh vọng người chơi');
                // showNotification('⚠️ Hệ Thống Danh Vọng', 'Không thể đọc dữ liệu danh vọng', 'warning', 3000);
                return;
            }
        } else {
            console.log('[Quản Lý Danh Vọng] Dữ liệu MVU chưa khởi tạo');
            return;
        }

        // 2. Xác định cấp độ danh vọng hiện tại
        let targetLevel = null;
        for (const level of REPUTATION_LEVELS) {
            if (playerReputation >= level.min && playerReputation <= level.max) {
                targetLevel = level;
                break;
            }
        }

        if (!targetLevel) {
            console.log('[Quản Lý Danh Vọng] Giá trị danh vọng vượt ngoài phạm vi thiết lập:', playerReputation);
            showNotification('⚠️ Hệ Thống Danh Vọng', `Giá trị danh vọng ${playerReputation} vượt ngoài phạm vi thiết lập`, 'warning', 3000);
            return;
        }

        // 3. Phát hiện xem có cần chuyển đổi cấp độ không
        const levelChanged = currentReputationLevel !== targetLevel.name;

        if (levelChanged && currentReputationLevel !== null) {
            // Cấp độ danh vọng thay đổi, hiển thị thông báo
            const oldLevel = currentReputationLevel;
            const newLevel = targetLevel.name;

            // Phán đoán là thăng cấp hay giáng cấp
            const oldLevelIndex = REPUTATION_LEVELS.findIndex(l => l.name === oldLevel);
            const newLevelIndex = REPUTATION_LEVELS.findIndex(l => l.name === newLevel);

            if (newLevelIndex > oldLevelIndex) {
                // Danh vọng tăng lên
                showNotification(
                    '🎉 Danh Vọng Tăng Lên!',
                    `Chúc mừng! Cấp bậc danh vọng của ngài từ【${oldLevel}】tăng lên【${newLevel}】`,
                    'success',
                    5000
                );
                console.log(`[Quản Lý Danh Vọng] Danh vọng tăng: ${oldLevel} → ${newLevel}`);
            } else {
                // Danh vọng giảm xuống
                showNotification(
                    '⚠️ Danh Vọng Giảm Xuống',
                    `Cấp bậc danh vọng của ngài từ【${oldLevel}】giảm xuống【${newLevel}】`,
                    'warning',
                    5000
                );
                console.log(`[Quản Lý Danh Vọng] Danh vọng giảm: ${oldLevel} → ${newLevel}`);
            }
        }

        // Cập nhật ghi chép cấp độ hiện tại
        currentReputationLevel = targetLevel.name;

        // 4. Lấy Worldbook
        let worldbookName = null;
        let worldbookEntries = null;

        // Thử nhiều cách để lấy Worldbook
        const allWorldbooks = getWorldbookNames();
        for (const wbName of allWorldbooks) {
            const entries = await getWorldbook(wbName);
            // Tìm mục bắt đầu bằng [Reputation]
            const hasReputationEntry = entries.some(e =>
                e.name && e.name.startsWith('[Reputation]')
            );

            if (hasReputationEntry) {
                worldbookName = wbName;
                worldbookEntries = entries;
                console.log('[Quản Lý Danh Vọng] Đã tìm thấy Worldbook chứa mục danh vọng:', wbName);
                break;
            }
        }

        if (!worldbookEntries) {
            console.log('[Quản Lý Danh Vọng] Không tìm thấy Worldbook chứa mục danh vọng');
            showNotification('⚠️ Hệ Thống Danh Vọng', 'Không tìm thấy mục cấp bậc danh vọng', 'error', 3000);
            return;
        }

        // 5. Cập nhật trạng thái mục danh vọng
        let hasUpdates = false;
        let successCount = 0;
        let failCount = 0;

        for (const level of REPUTATION_LEVELS) {
            // Tìm mục trong Lorebook khớp với 'comment'
            const entry = worldbookEntries.find(e => e.name === level.comment);

            if (entry) {
                const shouldEnable = (level.name === targetLevel.name);

                if (entry.enabled !== shouldEnable) {
                    entry.enabled = shouldEnable;
                    hasUpdates = true;
                    successCount++;
                    console.log(`[Quản Lý Danh Vọng] Mục ${level.name} -> ${shouldEnable ? 'Bật' : 'Tắt'}`);
                }
            } else {
                failCount++;
                console.log(`[Quản Lý Danh Vọng] Không tìm thấy mục: ${level.comment}`);
            }
        }

        // 6. Lưu cập nhật
        if (hasUpdates) {
            await replaceWorldbook(worldbookName, worldbookEntries);

            // Hiển thị kết quả cập nhật
            if (failCount === 0) {
                showNotification(
                    '✅ Hệ Thống Danh Vọng',
                    `Đã chuyển thành công sang【${targetLevel.name}】(${playerReputation} điểm)`,
                    'success',
                    3000
                );
            } else {
                showNotification(
                    '⚠️ Hệ Thống Danh Vọng',
                    `Chuyển sang【${targetLevel.name}】, nhưng có ${failCount} mục không tìm thấy`,
                    'warning',
                    4000
                );
            }

            // Làm mới trình chỉnh sửa
            if (typeof builtin !== 'undefined' && builtin.reloadEditorDebounced) {
                builtin.reloadEditorDebounced(worldbookName, false);
            }
        }

    } catch (error) {
        console.error('[Quản Lý Danh Vọng] Xảy ra lỗi:', error);
        showNotification('❌ Hệ Thống Danh Vọng', 'Chuyển đổi thất bại: ' + error.message, 'error', 5000);
    }
}

// Hàm hiển thị thông báo
function showNotification(title, message, type = 'info', duration = 3000) {
    // Sử dụng toastr hiển thị thông báo (nếu khả dụng)
    if (typeof toastr !== 'undefined') {
        const options = {
            timeOut: duration,
            extendedTimeOut: 1000,
            positionClass: 'toast-top-right',
            closeButton: true,
            progressBar: true
        };

        switch(type) {
            case 'success':
                toastr.success(message, title, options);
                break;
            case 'warning':
                toastr.warning(message, title, options);
                break;
            case 'error':
                toastr.error(message, title, options);
                break;
            default:
                toastr.info(message, title, options);
        }
    } else {
        // Dự phòng: Sử dụng console output
        console.log(`[${title}] ${message}`);
    }
}

// Kích hoạt kiểm tra thủ công (Dùng để debug)
window.checkPlayerReputation = async function() {
    const chatVariables = getVariables({ type: 'chat' });
    if (chatVariables && chatVariables.stat_data) {
        await checkAndUpdateReputation(chatVariables);
    } else {
        console.log('[Quản Lý Danh Vọng] Không thể lấy dữ liệu MVU');
    }
};

// Khởi tạo
(async () => {
    console.log('[Quản Lý Danh Vọng] Script tự động chuyển đổi danh vọng đã tải');
    console.log('[Quản Lý Danh Vọng] Sử dụng checkPlayerReputation() để kích hoạt kiểm tra thủ công');

    // Kiểm tra ban đầu có độ trễ
    setTimeout(async () => {
        const chatVariables = getVariables({ type: 'chat' });
        if (chatVariables && chatVariables.stat_data) {
            await checkAndUpdateReputation(chatVariables);
        }
    }, 2000);
})();

// Script tự động chuyển đổi cấp bậc mạo hiểm giả
// Chức năng: Dựa vào biến "player.playerAdventurerGuildRank" trong MVU để tự động bật tắt mục Lorebook tương ứng

// Cấu hình cấp bậc mạo hiểm giả
// Lưu ý: 'name' phải khớp với Value trong [InitVar], 'comment' phải khớp với Tên mục (Memo) trong Lorebook
const ADVENTURER_LEVELS = [
    { name: 'Mạo Hiểm Giả', comment: '[AdventurerLevel]Mạo Hiểm Giả', order: 0 },
