// Hàm kiểm tra cốt lõi
async function checkAndUpdateAdventurerLevel(mvuData) {
    try {
        // 1. Lấy cấp bậc mạo hiểm giả
        let adventurerLevel = null;
        let guildPoints = 0;

        if (mvuData && mvuData.stat_data) {
            // Lấy cấp độ (Sử dụng đường dẫn biến đã dịch: player.playerAdventurerGuildRank)
            const levelArray = mvuData.stat_data?.player?.playerAdventurerGuildRank;
            if (levelArray && Array.isArray(levelArray)) {
                adventurerLevel = levelArray[0];
                console.log('[Cấp Bậc Mạo Hiểm Giả] Cấp độ hiện tại:', adventurerLevel);
            }

            // Lấy điểm công tích (Sử dụng đường dẫn biến đã dịch: player.playerAdventurerMeritPoints)
            const pointsArray = mvuData.stat_data?.player?.playerAdventurerMeritPoints;
            if (pointsArray && Array.isArray(pointsArray)) {
                guildPoints = parseInt(pointsArray[0]); // Đảm bảo là số
                console.log('[Cấp Bậc Mạo Hiểm Giả] Điểm công tích hiện tại:', guildPoints);
            }
        }

        if (!adventurerLevel) {
            console.log('[Cấp Bậc Mạo Hiểm Giả] Không thể lấy dữ liệu cấp độ');
            return;
        }

        // 2. Tìm cấu hình cấp độ tương ứng
        const targetLevel = ADVENTURER_LEVELS.find(level => level.name === adventurerLevel);

        if (!targetLevel) {
            console.log('[Cấp Bậc Mạo Hiểm Giả] Cấp độ không xác định:', adventurerLevel);
            showLevelNotification('⚠️ Công Hội Mạo Hiểm', `Cấp độ không xác định: ${adventurerLevel}`, 'warning', 3000);
            return;
        }

        // 3. Phát hiện thay đổi cấp độ
        const levelChanged = currentAdventurerLevel !== targetLevel.name;

        if (levelChanged && currentAdventurerLevel !== null) {
            // Cấp độ thay đổi
            const oldLevel = currentAdventurerLevel;
            const newLevel = targetLevel.name;

            // Phán đoán là thăng cấp hay giáng cấp
            const oldLevelConfig = ADVENTURER_LEVELS.find(l => l.name === oldLevel);
            const newLevelConfig = ADVENTURER_LEVELS.find(l => l.name === newLevel);

            if (newLevelConfig.order > oldLevelConfig.order) {
                // Thăng cấp
                showLevelNotification(
                    '🎊 Công Hội Thăng Chức!',
                    `Chúc mừng! Ngài từ【${oldLevel}】thăng cấp lên【${newLevel}】Mạo Hiểm Giả!`,
                    'success',
                    6000
                );

                // Thông báo thăng cấp đặc biệt
                if (newLevel === 'Hoàng Kim') {
                    showLevelNotification(
                        '✨ Huyền Thoại Ra Đời',
                        'Ngài đã trở thành huyền thoại sống, chân dung ngài sẽ được treo tại đại sảnh công hội!',
                        'info',
                        5000
                    );
                } else if (newLevel === 'Bạch Kim') {
                    showLevelNotification(
                        '🌟 Vượt Qua Người Phàm',
                        'Ngài đã vượt qua giới hạn của người phàm, lịch sử sẽ ghi nhớ tên ngài!',
                        'info',
                        5000
                    );
                } else if (newLevel === 'Truyền Kỳ') {
                    showLevelNotification(
                        '⚡ Truyền Thuyết Bất Tử',
                        'Ngài đã trở thành truyền thuyết bất tử, ngài định nghĩa thế nào là mạo hiểm giả!',
                        'info',
                        8000
                    );
                }

                console.log(`[Cấp Bậc Mạo Hiểm Giả] Thăng cấp: ${oldLevel} → ${newLevel}`);
            } else {
                // Giáng cấp (Về lý thuyết không nên xảy ra, nhưng để cho trọn vẹn)
                showLevelNotification(
                    '⚠️ Điều Chỉnh Cấp Độ',
                    `Cấp bậc mạo hiểm giả của ngài từ【${oldLevel}】điều chỉnh thành【${newLevel}】`,
                    'warning',
                    5000
                );
                console.log(`[Cấp Bậc Mạo Hiểm Giả] Giáng cấp: ${oldLevel} → ${newLevel}`);
            }
        }

        // 4. Hiển thị tiến độ điểm công tích (Nếu gần thăng cấp)
        if (previousGuildPoints !== null && guildPoints > previousGuildPoints) {
            const pointsGained = guildPoints - previousGuildPoints;

            // Tính điểm cần cho cấp tiếp theo
            let nextLevelPoints = getNextLevelRequirement(adventurerLevel);
            if (nextLevelPoints) {
                const progress = ((guildPoints / nextLevelPoints) * 100).toFixed(1);

                // Nếu tiến độ vượt quá 80%, hiển thị nhắc nhở
                if (progress >= 80 && progress < 100) {
                    showLevelNotification(
                        '📊 Tiến Độ Thăng Cấp',
                        `Điểm công tích +${pointsGained}! Cách cấp tiếp theo còn ${nextLevelPoints - guildPoints} điểm (${progress}%)`,
                        'info',
                        3000
                    );
                }
            }
        }

        // Cập nhật ghi chép
        currentAdventurerLevel = targetLevel.name;
        previousGuildPoints = guildPoints;

        // 5. Lấy Worldbook và cập nhật mục
        const allWorldbooks = getWorldbookNames();
        let worldbookName = null;
        let worldbookEntries = null;

        for (const wbName of allWorldbooks) {
            const entries = await getWorldbook(wbName);
            const hasAdventurerEntry = entries.some(e =>
                e.name && e.name.startsWith('[AdventurerLevel]')
            );

            if (hasAdventurerEntry) {
                worldbookName = wbName;
                worldbookEntries = entries;
                console.log('[Cấp Bậc Mạo Hiểm Giả] Đã tìm thấy Worldbook chứa mục cấp độ:', wbName);
                break;
            }
        }

        if (!worldbookEntries) {
            console.log('[Cấp Bậc Mạo Hiểm Giả] Không tìm thấy Worldbook chứa mục cấp độ');
            if (levelChanged) {
                showLevelNotification(
                    '⚠️ Công Hội Mạo Hiểm',
                    'Không tìm thấy mục cấp độ, vui lòng kiểm tra cài đặt Worldbook',
                    'error',
                    4000
                );
            }
            return;
        }

        // 6. Cập nhật trạng thái mục
        let hasUpdates = false;

        for (const level of ADVENTURER_LEVELS) {
            const entry = worldbookEntries.find(e => e.name === level.comment);

            if (entry) {
                const shouldEnable = (level.name === targetLevel.name);

                if (entry.enabled !== shouldEnable) {
                    entry.enabled = shouldEnable;
                    hasUpdates = true;
                    console.log(`[Cấp Bậc Mạo Hiểm Giả] Mục ${level.name} -> ${shouldEnable ? 'Bật' : 'Tắt'}`);
                }
            }
        }

        // 7. Lưu cập nhật
        if (hasUpdates) {
            await replaceWorldbook(worldbookName, worldbookEntries);

            if (!levelChanged) {
                // Cập nhật ngầm khi khởi tạo
                console.log(`[Cấp Bậc Mạo Hiểm Giả] Mục đã đồng bộ đến【${targetLevel.name}】`);
            }

            // Làm mới trình chỉnh sửa
            if (typeof builtin !== 'undefined' && builtin.reloadEditorDebounced) {
                builtin.reloadEditorDebounced(worldbookName, false);
            }
        }

    } catch (error) {
        console.error('[Cấp Bậc Mạo Hiểm Giả] Xảy ra lỗi:', error);
        showLevelNotification('❌ Công Hội Mạo Hiểm', 'Chuyển đổi cấp độ thất bại: ' + error.message, 'error', 5000);
    }
}

// Lấy yêu cầu điểm công tích cho cấp tiếp theo
function getNextLevelRequirement(currentLevel) {
    // Cập nhật Key theo tên tiếng Việt
    const requirements = {
        'Mạo Hiểm Giả': 100,
        'Đồng Thau': 1000,
        'Tinh Thiết': 10000,
        'Bạch Ngân': 100000,
        'Hoàng Kim': 1000000,
        'Bạch Kim': 10000000,
        'Kim Cương': 100000000,
        'Long Tinh': 1000000000,
        'Truyền Kỳ': null // Đã đạt cấp cao nhất
    };

    return requirements[currentLevel];
}

// Hàm hiển thị thông báo
function showLevelNotification(title, message, type = 'info', duration = 3000) {
    if (typeof toastr !== 'undefined') {
        const options = {
            timeOut: duration,
            extendedTimeOut: 1000,
            positionClass: 'toast-top-right',
            closeButton: true,
            progressBar: true
        };

        // Thêm kiểu dáng đặc biệt cho thông báo thăng cấp
        if (title.includes('Thăng Chức')) {
            options.positionClass = 'toast-top-center';
            options.timeOut = duration;
        }

        switch(type) {
            case 'success':
                toastr.success(message, title, options);
                break;
            case 'warning':
                toastr.warning(message, title, options);
                break;
            case 'error':
                toastr.error(message, title, options);
                break;
            default:
                toastr.info(message, title, options);
        }
    } else {
        console.log(`[${title}] ${message}`);
    }
}

