// Hàm kiểm tra cốt lõi
async function checkAndUpdateMagicLevel(mvuData) {
    try {
        // 1. Lấy cấp bậc ma pháp và tiến độ tu luyện
        let magicLevel = null;
        let magicProgress = null;

        if (mvuData && mvuData.stat_data) {
            // Lấy cấp bậc ma pháp (Sử dụng đường dẫn biến đã dịch: player.playerMagicLevel)
            const levelArray = mvuData.stat_data?.player?.playerMagicLevel;
            if (levelArray && Array.isArray(levelArray)) {
                magicLevel = levelArray[0];
                console.log('[Cấp Bậc Ma Pháp] Cấp độ hiện tại:', magicLevel);
            }

            // Lấy tiến độ tu luyện (Sử dụng đường dẫn biến đã dịch: player.playerMagicTrainingProgress)
            const progressArray = mvuData.stat_data?.player?.playerMagicTrainingProgress;
            if (progressArray && Array.isArray(progressArray)) {
                magicProgress = progressArray[0];
                console.log('[Cấp Bậc Ma Pháp] Tiến độ tu luyện:', magicProgress);
            }
        }

        if (!magicLevel) {
            console.log('[Cấp Bậc Ma Pháp] Không thể lấy dữ liệu cấp bậc ma pháp');
            showMagicNotification('⚠️ Hệ Thống Ma Pháp', 'Không thể đọc dữ liệu cấp bậc ma pháp', 'warning', 3000);
            return;
        }

        // 2. Tìm cấu hình cấp độ tương ứng
        const targetLevel = MAGIC_LEVELS.find(level => level.name === magicLevel);

        if (!targetLevel) {
            console.log('[Cấp Bậc Ma Pháp] Cấp độ không xác định:', magicLevel);
            showMagicNotification('⚠️ Hệ Thống Ma Pháp', `Cấp độ không xác định: ${magicLevel}`, 'warning', 3000);
            return;
        }

        // 3. Phát hiện thay đổi cấp độ (Đột phá)
        const levelChanged = currentMagicLevel !== targetLevel.name;

        if (levelChanged && currentMagicLevel !== null) {
            // Ma pháp đột phá!
            const oldLevel = currentMagicLevel;
            const newLevel = targetLevel.name;

            // Phán đoán là đột phá hay rớt cấp
            const oldLevelConfig = MAGIC_LEVELS.find(l => l.name === oldLevel);
            const newLevelConfig = MAGIC_LEVELS.find(l => l.name === newLevel);

            if (newLevelConfig.order > oldLevelConfig.order) {
                // Đột phá cảnh giới
                showMagicNotification(
                    '✨ Cảnh Giới Đột Phá!',
                    `Chúc mừng! Cảnh giới ma pháp của ngài từ【${oldLevel}】đột phá lên【${newLevel}】!`,
                    'success',
                    7000
                );

                // Thông báo bổ sung cho cảnh giới đặc biệt
                if (newLevel === 'Ngũ Giai Hi Quang') {
                    showMagicNotification(
                        '🌅 Chạm Vào Quy Tắc',
                        'Ngài bắt đầu chạm vào biên giới của quy tắc tự nhiên, ma lực như ánh bình minh vĩnh hằng!',
                        'info',
                        5000
                    );
                } else if (newLevel === 'Thất Giai Tinh Hà') {
                    showMagicNotification(
                        '🌌 Tinh Hà Chi Chủ',
                        'Ngài đã trở thành bản thân ma pháp, tinh hà lưu chuyển trong ý niệm của ngài!',
                        'info',
                        5000
                    );
                } else if (newLevel === 'Cửu Giai Tinh Thần') {
                    showMagicNotification(
                        '⚡ Bán Thần Chi Cảnh',
                        'Ngài đứng trên ranh giới giữa người phàm và thần minh, lắng nghe lời cầu nguyện của tín đồ...',
                        'info',
                        8000
                    );
                }

                console.log(`[Cấp Bậc Ma Pháp] Đột phá cảnh giới: ${oldLevel} → ${newLevel}`);
            } else {
                // Rớt cảnh giới (Thường sẽ không xảy ra)
                showMagicNotification(
                    '⚠️ Cảnh Giới Rơi Xuống',
                    `Cảnh giới ma pháp của ngài từ【${oldLevel}】rơi xuống【${newLevel}】`,
                    'warning',
                    5000
                );
                console.log(`[Cấp Bậc Ma Pháp] Cảnh giới rơi xuống: ${oldLevel} → ${newLevel}`);
            }
        }

        // 4. Phân tích và hiển thị tiến độ tu luyện
        if (magicProgress && targetLevel.nextLevel) {
            // Phân tích định dạng tiến độ "Hiện tại/100000"
            const progressMatch = magicProgress.match(/(\d+)\/(\d+)/);
            if (progressMatch) {
                const current = parseInt(progressMatch[1]);
                const max = parseInt(progressMatch[2]);
                const percentage = ((current / max) * 100).toFixed(1);

                // Phát hiện tăng trưởng tiến độ
                if (previousProgress) {
                    const prevMatch = previousProgress.match(/(\d+)\/(\d+)/);
                    if (prevMatch) {
                        const prevCurrent = parseInt(prevMatch[1]);
                        const gain = current - prevCurrent;

                        if (gain > 0) {
                            // Hiển thị thông báo khác nhau dựa trên tiến độ
                            if (percentage >= 90) {
                                showMagicNotification(
                                    '🔥 Sắp Sửa Đột Phá!',
                                    `Tiến độ tu luyện +${gain}! Tiến độ hiện tại ${percentage}%, sắp đột phá lên【${targetLevel.nextLevel}】!`,
                                    'info',
                                    4000
                                );
                            } else if (percentage >= 70) {
                                showMagicNotification(
                                    '📈 Tu Luyện Tinh Tiến',
                                    `Tiến độ tu luyện +${gain}! Tiến độ hiện tại ${percentage}%, tiếp tục nỗ lực!`,
                                    'info',
                                    3000
                                );
                            } else if (gain >= 1000) {
                                // Hiển thị khi tiến bộ lớn
                                showMagicNotification(
                                    '⚡ Đốn Ngộ!',
                                    `Tiến độ tu luyện tăng vọt +${gain}! Tiến độ hiện tại ${percentage}%`,
                                    'success',
                                    3500
                                );
                            }
                        }
                    }
                }
            }
        }

        // Cập nhật ghi chép
        currentMagicLevel = targetLevel.name;
        previousProgress = magicProgress;

        // 5. Lấy Worldbook và cập nhật mục
        const allWorldbooks = getWorldbookNames();
        let worldbookName = null;
        let worldbookEntries = null;

        for (const wbName of allWorldbooks) {
            const entries = await getWorldbook(wbName);
            const hasMagicEntry = entries.some(e =>
                e.name && e.name.startsWith('[MagicLevel]')
            );

            if (hasMagicEntry) {
                worldbookName = wbName;
                worldbookEntries = entries;
                console.log('[Cấp Bậc Ma Pháp] Đã tìm thấy Worldbook chứa mục ma pháp:', wbName);
                break;
            }
        }

        if (!worldbookEntries) {
            console.log('[Cấp Bậc Ma Pháp] Không tìm thấy Worldbook chứa mục ma pháp');
            if (levelChanged) {
                showMagicNotification(
                    '❌ Hệ Thống Ma Pháp',
                    'Không tìm thấy mục cấp bậc ma pháp, vui lòng kiểm tra cài đặt Worldbook',
                    'error',
                    4000
                );
            }
            return;
        }

        // 6. Cập nhật trạng thái mục
        let hasUpdates = false;
        let successCount = 0;
        let failCount = 0;

        for (const level of MAGIC_LEVELS) {
            const entry = worldbookEntries.find(e => e.name === level.comment);

            if (entry) {
                const shouldEnable = (level.name === targetLevel.name);

                if (entry.enabled !== shouldEnable) {
                    entry.enabled = shouldEnable;
                    hasUpdates = true;
                    successCount++;
                    console.log(`[Cấp Bậc Ma Pháp] Mục ${level.name} -> ${shouldEnable ? 'Bật' : 'Tắt'}`);
                }
            } else {
                if (level.name === targetLevel.name) {
                    failCount++;
                    console.log(`[Cấp Bậc Ma Pháp] Cảnh báo: Không tìm thấy mục cấp độ hiện tại: ${level.comment}`);
                }
            }
        }

        // 7. Lưu cập nhật
        if (hasUpdates) {
            await replaceWorldbook(worldbookName, worldbookEntries);

            // Hiển thị kết quả chuyển đổi
            if (failCount === 0) {
                if (!levelChanged) {
                    // Khởi tạo thành công
                    showMagicNotification(
                        '✅ Hệ Thống Ma Pháp',
                        `Cấp bậc ma pháp đã đồng bộ:【${targetLevel.name}】`,
                        'success',
                        2500
                    );
                }
            } else {
                showMagicNotification(
                    '⚠️ Hệ Thống Ma Pháp',
                    `Chuyển sang【${targetLevel.name}】, nhưng thiếu ${failCount} mục Lorebook`,
                    'warning',
                    4000
                );
            }

            // Làm mới trình chỉnh sửa
            if (typeof builtin !== 'undefined' && builtin.reloadEditorDebounced) {
                builtin.reloadEditorDebounced(worldbookName, false);
            }
        }

    } catch (error) {
        console.error('[Cấp Bậc Ma Pháp] Xảy ra lỗi:', error);
        showMagicNotification('❌ Hệ Thống Ma Pháp', 'Chuyển đổi cấp độ thất bại: ' + error.message, 'error', 5000);
    }
}

