// Script tự động chuyển đổi cấp bậc nhục thể
// Chức năng: Dựa vào biến "player.playerPhysicalLevel" trong MVU để tự động bật tắt mục Lorebook tương ứng

// Cấu hình cấp bậc nhục thể
// Lưu ý: 'name' phải khớp với Value trong [InitVar], 'comment' phải khớp với Tên mục (Memo) trong Lorebook
const PHYSICAL_LEVELS = [
    { name: 'Nhất Giai Chúc Cốt', comment: '[PhysicalLevel]Nhất Giai Chúc Cốt', order: 1, nextLevel: 'Nhị Giai Thối Bì' },
    { name: 'Nhị Giai Thối Bì', comment: '[PhysicalLevel]Nhị Giai Thối Bì', order: 2, nextLevel: 'Tam Giai Luyện Cân' },
    { name: 'Tam Giai Luyện Cân', comment: '[PhysicalLevel]Tam Giai Luyện Cân', order: 3, nextLevel: 'Tứ Giai Ngưng Huyết' },
    { name: 'Tứ Giai Ngưng Huyết', comment: '[PhysicalLevel]Tứ Giai Ngưng Huyết', order: 4, nextLevel: 'Ngũ Giai Kim Cương' },
    { name: 'Ngũ Giai Kim Cương', comment: '[PhysicalLevel]Ngũ Giai Kim Cương', order: 5, nextLevel: 'Lục Giai Nhạc Lập' },
    { name: 'Lục Giai Nhạc Lập', comment: '[PhysicalLevel]Lục Giai Nhạc Lập', order: 6, nextLevel: 'Thất Giai Phá Hạn' },
    { name: 'Thất Giai Phá Hạn', comment: '[PhysicalLevel]Thất Giai Phá Hạn', order: 7, nextLevel: 'Bát Giai Thánh Khu' },
    { name: 'Bát Giai Thánh Khu', comment: '[PhysicalLevel]Bát Giai Thánh Khu', order: 8, nextLevel: 'Cửu Giai Võ Thần' },
    { name: 'Cửu Giai Võ Thần', comment: '[PhysicalLevel]Cửu Giai Võ Thần', order: 9, nextLevel: null }
];

// Ghi lại cấp độ và tiến độ hiện tại
let currentPhysicalLevel = null;
let previousPhysicalProgress = null;

