// Hàm kiểm tra cốt lõi
async function checkAndUpdatePhysicalLevel(mvuData) {
    try {
        // 1. Lấy cấp bậc nhục thể và tiến độ tu luyện
        let physicalLevel = null;
        let physicalProgress = null;

        if (mvuData && mvuData.stat_data) {
            // Lấy cấp bậc nhục thể (Sử dụng đường dẫn biến đã dịch: player.playerPhysicalLevel)
            const levelArray = mvuData.stat_data?.player?.playerPhysicalLevel;
            if (levelArray && Array.isArray(levelArray)) {
                physicalLevel = levelArray[0];
                console.log('[Cấp Bậc Nhục Thể] Cấp độ hiện tại:', physicalLevel);
            }

            // Lấy tiến độ tu luyện (Sử dụng đường dẫn biến đã dịch: player.playerPhysicalTrainingProgress)
            const progressArray = mvuData.stat_data?.player?.playerPhysicalTrainingProgress;
            if (progressArray && Array.isArray(progressArray)) {
                physicalProgress = progressArray[0];
                console.log('[Cấp Bậc Nhục Thể] Tiến độ tu luyện:', physicalProgress);
            }
        }

        if (!physicalLevel) {
            console.log('[Cấp Bậc Nhục Thể] Không thể lấy dữ liệu cấp bậc nhục thể');
            return;
        }

        // 2. Tìm cấu hình cấp độ tương ứng
        const targetLevel = PHYSICAL_LEVELS.find(level => level.name === physicalLevel);

        if (!targetLevel) {
            console.log('[Cấp Bậc Nhục Thể] Cấp bậc nhục thể không xác định:', physicalLevel);
            showPhysicalNotification('⚠️ Hệ Thống Võ Đạo', `Cấp bậc nhục thể không xác định: ${physicalLevel}`, 'warning', 3000);
            return;
        }

        // 3. Phát hiện thay đổi cấp độ (Đột phá)
        const levelChanged = currentPhysicalLevel !== targetLevel.name;

        if (levelChanged && currentPhysicalLevel !== null) {
            // Võ đạo đột phá!
            const oldLevel = currentPhysicalLevel;
            const newLevel = targetLevel.name;

            // Phán đoán là đột phá hay rớt cấp
            const oldLevelConfig = PHYSICAL_LEVELS.find(l => l.name === oldLevel);
            const newLevelConfig = PHYSICAL_LEVELS.find(l => l.name === newLevel);

            if (newLevelConfig.order > oldLevelConfig.order) {
                // Đột phá cảnh giới
                showPhysicalNotification(
                    '💪 Võ Đạo Đột Phá!',
                    `Chúc mừng! Cảnh giới nhục thể của ngài từ【${oldLevel}】đột phá lên【${newLevel}】!`,
                    'success',
                    7000
                );

                // Thông báo bổ sung cho cảnh giới đặc biệt
                if (newLevel === 'Ngũ Giai Kim Cương') {
                    showPhysicalNotification(
                        '🛡️ Kim Cương Bất Hoại',
                        'Cơ thể ngài như vàng đúc sắt đánh, đao thương bất nhập, thủy hỏa bất xâm!',
                        'info',
                        5000
                    );
                } else if (newLevel === 'Thất Giai Phá Hạn') {
                    showPhysicalNotification(
                        '⚡ Đột Phá Giới Hạn',
                        'Ngài đã phá vỡ mọi giới hạn của nhân loại, tiến vào tầng thứ sinh mệnh hoàn toàn mới!',
                        'info',
                        5000
                    );
                } else if (newLevel === 'Bát Giai Thánh Khu') {
                    showPhysicalNotification(
                        '✨ Thành Tựu Thánh Khu',
                        'Cơ thể ngài đã thần thánh hóa, trở thành trọng khí quốc gia, cường giả ẩn thế!',
                        'info',
                        6000
                    );
                } else if (newLevel === 'Cửu Giai Võ Thần') {
                    showPhysicalNotification(
                        '⚔️ Võ Thần Giáng Thế',
                        'Ngài đã đứng trên ranh giới giữa người phàm và thần minh, Thần của Võ Đạo!',
                        'info',
                        8000
                    );
                }

                console.log(`[Cấp Bậc Nhục Thể] Đột phá cảnh giới: ${oldLevel} → ${newLevel}`);
            } else {
                // Rớt cảnh giới
                showPhysicalNotification(
                    '⚠️ Cảnh Giới Rơi Xuống',
                    `Cảnh giới nhục thể của ngài từ【${oldLevel}】rơi xuống【${newLevel}】`,
                    'warning',
                    5000
                );
                console.log(`[Cấp Bậc Nhục Thể] Cảnh giới rơi xuống: ${oldLevel} → ${newLevel}`);
            }
        }

        // 4. Phân tích và hiển thị tiến độ tu luyện
        if (physicalProgress && targetLevel.nextLevel) {
            // Phân tích định dạng tiến độ "Hiện tại/100000"
            const progressMatch = physicalProgress.match(/(\d+)\/(\d+)/);
            if (progressMatch) {
                const current = parseInt(progressMatch[1]);
                const max = parseInt(progressMatch[2]);
                const percentage = ((current / max) * 100).toFixed(1);

                // Phát hiện tăng trưởng tiến độ
                if (previousPhysicalProgress) {
                    const prevMatch = previousPhysicalProgress.match(/(\d+)\/(\d+)/);
                    if (prevMatch) {
                        const prevCurrent = parseInt(prevMatch[1]);
                        const gain = current - prevCurrent;

                        if (gain > 0) {
                            // Hiển thị thông báo khác nhau dựa trên tiến độ
                            if (percentage >= 90) {
                                showPhysicalNotification(
                                    '🔥 Sắp Sửa Đột Phá!',
                                    `Tiến độ tu luyện +${gain}! Tiến độ hiện tại ${percentage}%, sắp đột phá lên【${targetLevel.nextLevel}】!`,
                                    'info',
                                    4000
                                );
                            } else if (percentage >= 70) {
                                showPhysicalNotification(
                                    '💯 Tinh Tiến Không Ngừng',
                                    `Tiến độ tu luyện +${gain}! Tiến độ hiện tại ${percentage}%, tiếp tục tôi luyện!`,
                                    'info',
                                    3000
                                );
                            } else if (gain >= 1000) {
                                // Hiển thị khi tiến bộ lớn
                                showPhysicalNotification(
                                    '⚡ Võ Đạo Đốn Ngộ!',
                                    `Tiến độ tu luyện tăng vọt +${gain}! Tiến độ hiện tại ${percentage}%`,
                                    'success',
                                    3500
                                );
                            }
                        }
                    }
                }
            }
        }

        // Cập nhật ghi chép
        currentPhysicalLevel = targetLevel.name;
        previousPhysicalProgress = physicalProgress;

        // 5. Lấy Worldbook và cập nhật mục
        const allWorldbooks = getWorldbookNames();
        let worldbookName = null;
        let worldbookEntries = null;

        for (const wbName of allWorldbooks) {
            const entries = await getWorldbook(wbName);
            // Tìm kiếm mục bắt đầu bằng [PhysicalLevel]
            const hasPhysicalEntry = entries.some(e =>
                e.name && e.name.startsWith('[PhysicalLevel]')
            );

            if (hasPhysicalEntry) {
                worldbookName = wbName;
                worldbookEntries = entries;
                console.log('[Cấp Bậc Nhục Thể] Đã tìm thấy Worldbook chứa mục nhục thể:', wbName);
                break;
            }
        }

        if (!worldbookEntries) {
            console.log('[Cấp Bậc Nhục Thể] Không tìm thấy Worldbook chứa mục nhục thể');
            if (levelChanged) {
                showPhysicalNotification(
                    '❌ Hệ Thống Võ Đạo',
                    'Không tìm thấy mục Cấp bậc nhục thể, vui lòng kiểm tra cài đặt Worldbook',
                    'error',
                    4000
                );
            }
            return;
        }

        // 6. Cập nhật trạng thái mục
        let hasUpdates = false;
        let successCount = 0;
        let failCount = 0;

        for (const level of PHYSICAL_LEVELS) {
            // Tìm mục trong Lorebook có tên (Memo) khớp với 'comment'
            const entry = worldbookEntries.find(e => e.name === level.comment);

            if (entry) {
                const shouldEnable = (level.name === targetLevel.name);

                if (entry.enabled !== shouldEnable) {
                    entry.enabled = shouldEnable;
                    hasUpdates = true;
                    successCount++;
                    console.log(`[Cấp Bậc Nhục Thể] Mục ${level.name} -> ${shouldEnable ? 'Bật' : 'Tắt'}`);
                }
            } else {
                if (level.name === targetLevel.name) {
                    failCount++;
                    console.log(`[Cấp Bậc Nhục Thể] Cảnh báo: Không tìm thấy mục cấp độ hiện tại: ${level.comment}`);
                }
            }
        }

        // 7. Lưu cập nhật và hiển thị kết quả
        if (hasUpdates) {
            try {
                await replaceWorldbook(worldbookName, worldbookEntries);

                // Hiển thị kết quả chuyển đổi
                if (failCount === 0) {
                    // Thành công hoàn toàn
                    if (!levelChanged) {
                        // Khởi tạo thành công
                        showPhysicalNotification(
                            '✅ Hệ Thống Võ Đạo',
                            `Cấp bậc nhục thể đã đồng bộ:【${targetLevel.name}】`,
                            'success',
                            2500
                        );
                    } else {
                        // Chuyển đổi thành công
                        showPhysicalNotification(
                            '✅ Chuyển Đổi Thành Công',
                            `Đã chuyển thành công sang cảnh giới【${targetLevel.name}】`,
                            'success',
                            3000
                        );
                    }
                } else {
                    // Thành công một phần
                    showPhysicalNotification(
                        '⚠️ Thành Công Một Phần',
                        `Chuyển sang【${targetLevel.name}】, nhưng thiếu ${failCount} mục Lorebook`,
                        'warning',
                        4000
                    );
                }

                // Làm mới trình chỉnh sửa
                if (typeof builtin !== 'undefined' && builtin.reloadEditorDebounced) {
                    builtin.reloadEditorDebounced(worldbookName, false);
                }
            } catch (error) {
                // Lưu thất bại
                console.error('[Cấp Bậc Nhục Thể] Lưu Worldbook thất bại:', error);
                showPhysicalNotification(
                    '❌ Chuyển Đổi Thất Bại',
                    `Không thể lưu thay đổi Worldbook: ${error.message}`,
                    'error',
                    5000
                );
            }
        } else if (levelChanged) {
            // Không có mục cần cập nhật nhưng cấp độ đã thay đổi (có thể do mục đã đúng trạng thái)
            showPhysicalNotification(
                '⚠️ Hệ Thống Võ Đạo',
                `Cấp độ đã là【${targetLevel.name}】, không cần chuyển đổi`,
                'info',
                2500
            );
        }

    } catch (error) {
        console.error('[Cấp Bậc Nhục Thể] Xảy ra lỗi:', error);
        showPhysicalNotification('❌ Hệ Thống Võ Đạo', 'Chuyển đổi cấp độ thất bại: ' + error.message, 'error', 5000);
    }
}

